package agent

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// LintHookErrorKind classifies infra failures returned by the pre-dispatch
// lint hook. The execute loop treats these as fail-open warnings rather than
// quality-policy results.
type LintHookErrorKind string

const (
	LintHookErrorKindMissingSkill    LintHookErrorKind = "missing-skill"
	LintHookErrorKindMissingHarness  LintHookErrorKind = "missing-harness"
	LintHookErrorKindEmptyOutput     LintHookErrorKind = "empty-output"
	LintHookErrorKindBadJSON         LintHookErrorKind = "bad-json"
	LintHookErrorKindCanceled        LintHookErrorKind = "canceled"
	LintHookErrorKindDispatchFailure LintHookErrorKind = "dispatch-failure"
)

// LintHookError is a typed infrastructure error returned by the lint hook.
// The Kind field is stable for errors.Is comparisons; Err carries the wrapped
// cause for logs and diagnostics.
type LintHookError struct {
	Kind LintHookErrorKind
	Err  error
}

func (e *LintHookError) Error() string {
	if e == nil {
		return "<nil>"
	}
	if e.Err == nil {
		return "lint hook: " + string(e.Kind)
	}
	return fmt.Sprintf("lint hook: %s: %v", e.Kind, e.Err)
}

func (e *LintHookError) Unwrap() error {
	if e == nil {
		return nil
	}
	return e.Err
}

func (e *LintHookError) Is(target error) bool {
	t, ok := target.(*LintHookError)
	if !ok || e == nil || t == nil {
		return false
	}
	return e.Kind == t.Kind
}

var (
	ErrLintHookMissingSkill   = &LintHookError{Kind: LintHookErrorKindMissingSkill}
	ErrLintHookMissingHarness = &LintHookError{Kind: LintHookErrorKindMissingHarness}
	ErrLintHookEmptyOutput    = &LintHookError{Kind: LintHookErrorKindEmptyOutput}
	ErrLintHookBadJSON        = &LintHookError{Kind: LintHookErrorKindBadJSON}
	ErrLintHookCanceled       = &LintHookError{Kind: LintHookErrorKindCanceled}
	ErrLintHookDispatch       = &LintHookError{Kind: LintHookErrorKindDispatchFailure}
)

type lintPromptBead struct {
	ID          string         `json:"id"`
	Title       string         `json:"title"`
	Type        string         `json:"type"`
	Labels      []string       `json:"labels,omitempty"`
	Parent      string         `json:"parent,omitempty"`
	Deps        []string       `json:"deps,omitempty"`
	Description string         `json:"description,omitempty"`
	Acceptance  string         `json:"acceptance,omitempty"`
	Notes       string         `json:"notes,omitempty"`
	Custom      map[string]any `json:"custom_fields,omitempty"`
}

// NewPreDispatchLintHook constructs the bead-lifecycle lint hook used before
// execute-loop dispatch.
func NewPreDispatchLintHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner) func(ctx context.Context, beadID string) (LintResult, error) {
	return func(ctx context.Context, beadID string) (LintResult, error) {
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindCanceled, Err: err}
			}
		}
		if strings.TrimSpace(rcfg.Harness()) == "" {
			return LintResult{}, ErrLintHookMissingHarness
		}
		if !hasBeadLifecycleSkill(projectRoot) {
			return LintResult{}, ErrLintHookMissingSkill
		}
		if store == nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("bead reader required")}
		}

		b, err := store.Get(beadID)
		if err != nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: fmt.Errorf("load bead %s: %w", beadID, err)}
		}

		prompt, err := buildPreDispatchLintPrompt(b)
		if err != nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: err}
		}

		result, err := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, AgentRunRuntime{
			Prompt:       prompt,
			WorkDir:      projectRoot,
			PromptSource: "bead-lifecycle-lint",
		})
		if err != nil {
			switch {
			case errors.Is(err, context.Canceled), errors.Is(err, context.DeadlineExceeded):
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindCanceled, Err: err}
			case isUnknownHarnessError(err):
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindMissingHarness, Err: err}
			case isMissingSkillError(err):
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindMissingSkill, Err: err}
			default:
				return LintResult{}, &LintHookError{Kind: LintHookErrorKindDispatchFailure, Err: err}
			}
		}

		payload, parseErr := lintResultPayload(result)
		if parseErr != nil {
			return LintResult{}, parseErr
		}
		var out LintResult
		if err := json.Unmarshal([]byte(payload), &out); err != nil {
			return LintResult{}, &LintHookError{Kind: LintHookErrorKindBadJSON, Err: err}
		}
		return out, nil
	}
}

func buildPreDispatchLintPrompt(b *bead.Bead) (string, error) {
	env := lintPromptBead{
		ID:          b.ID,
		Title:       strings.TrimSpace(b.Title),
		Type:        b.IssueType,
		Labels:      append([]string(nil), b.Labels...),
		Parent:      strings.TrimSpace(b.Parent),
		Deps:        append([]string(nil), b.DepIDs()...),
		Description: strings.TrimSpace(b.Description),
		Acceptance:  strings.TrimSpace(b.Acceptance),
		Notes:       strings.TrimSpace(b.Notes),
	}
	if len(b.Extra) > 0 {
		env.Custom = make(map[string]any, len(b.Extra))
		for k, v := range b.Extra {
			env.Custom[k] = v
		}
	}

	body, err := json.MarshalIndent(env, "", "  ")
	if err != nil {
		return "", err
	}

	var sb strings.Builder
	sb.WriteString("MODE: lint\n")
	sb.WriteString("You are the bead-lifecycle skill. Score the bead below using lint mode and return exactly one JSON object matching LintResult.\n")
	sb.WriteString("Return only JSON with these top-level fields.\n")
	sb.WriteString("Required output shape example: {\"score\":0,\"rationale\":\"\",\"suggested_fixes\":[],\"waivers_applied\":[]}\n")
	sb.WriteString("Do not wrap the answer in markdown or prose.\n\n")
	sb.WriteString("```json\n")
	sb.Write(body)
	sb.WriteString("\n```\n")
	return sb.String(), nil
}

func lintResultPayload(result *Result) (string, error) {
	if result == nil {
		return "", &LintHookError{Kind: LintHookErrorKindEmptyOutput, Err: fmt.Errorf("nil result")}
	}
	text := strings.TrimSpace(result.CondensedOutput)
	if text == "" {
		text = strings.TrimSpace(result.Output)
	}
	if text == "" {
		return "", ErrLintHookEmptyOutput
	}
	candidate, ok := extractJSONCandidate(text)
	if !ok {
		return "", &LintHookError{Kind: LintHookErrorKindBadJSON, Err: fmt.Errorf("no JSON object found")}
	}
	return candidate, nil
}

func hasBeadLifecycleSkill(projectRoot string) bool {
	if strings.TrimSpace(projectRoot) == "" {
		return false
	}
	candidates := []string{
		filepath.Join(projectRoot, ".agents", "skills", "ddx", "bead-lifecycle", "SKILL.md"),
		filepath.Join(projectRoot, ".claude", "skills", "ddx", "bead-lifecycle", "SKILL.md"),
	}
	for _, p := range candidates {
		if _, err := os.Stat(p); err == nil {
			return true
		}
	}
	return false
}

func isUnknownHarnessError(err error) bool {
	if err == nil {
		return false
	}
	s := strings.ToLower(err.Error())
	return strings.Contains(s, "unknown harness") || strings.Contains(s, "harness not found")

package agent

import "context"

// PreClaimIntakeOutcome classifies the pre-claim intake decision for a bead.
// Only actionable_atomic proceeds directly to Claim; intake_error fail-opens.
type PreClaimIntakeOutcome string

const (
	PreClaimIntakeActionableAtomic       PreClaimIntakeOutcome = "actionable_atomic"
	PreClaimIntakeActionableButRewritten PreClaimIntakeOutcome = "actionable_but_rewritten"
	PreClaimIntakeTooLargeDecomposed     PreClaimIntakeOutcome = "too_large_decomposed"
	PreClaimIntakeAmbiguousNeedsHuman    PreClaimIntakeOutcome = "ambiguous_needs_human"
	PreClaimIntakeError                  PreClaimIntakeOutcome = "intake_error"
)

// PreClaimIntakeResult is the typed decision returned by the intake hook.
// Detail carries the human-readable rationale or infra failure context.
type PreClaimIntakeResult struct {
	Outcome PreClaimIntakeOutcome `json:"outcome,omitempty"`
	Detail  string                `json:"detail,omitempty"`
}

// PreClaimIntakeHook classifies a ready bead before Claim. The loop treats
// actionable_atomic as pass-through, skips Claim for non-atomic outcomes, and
// fail-opens when the hook returns an infrastructure error.
type PreClaimIntakeHook func(ctx context.Context, beadID string) (PreClaimIntakeResult, error)

func (r PreClaimIntakeResult) normalizedOutcome() PreClaimIntakeOutcome {
	switch r.Outcome {
	case "", PreClaimIntakeActionableAtomic:
		return PreClaimIntakeActionableAtomic
	case PreClaimIntakeActionableButRewritten, PreClaimIntakeTooLargeDecomposed,
		PreClaimIntakeAmbiguousNeedsHuman, PreClaimIntakeError:
		return r.Outcome
	default:
		return PreClaimIntakeError
	}
}

package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// PreClaimIntakePromptSource identifies the pre-claim complexity-eval
// dispatch in session logs and tests.
const PreClaimIntakePromptSource = "bead-lifecycle-intake"

type preClaimIntakePromptEnvelope struct {
	Title         string                  `json:"title"`
	Description   string                  `json:"description"`
	Acceptance    string                  `json:"acceptance"`
	Labels        []string                `json:"labels"`
	PriorAttempts []preClaimIntakeAttempt `json:"prior_attempts"`
	Depth         int                     `json:"depth"`
	Parent        string                  `json:"parent,omitempty"`
	Dependencies  []string                `json:"dependencies,omitempty"`
}

type preClaimIntakeAttempt struct {
	Status    string `json:"status"`
	Rationale string `json:"rationale,omitempty"`
}

type preClaimIntakePromptResult struct {
	Classification string  `json:"classification"`
	Confidence     float64 `json:"confidence,omitempty"`
	Reasoning      string  `json:"reasoning,omitempty"`
}

// NewPreClaimIntakeHook constructs the bead-intake complexity gate used
// before claim in the work / execute-loop paths. The hook evaluates the bead
// using the repository's triage prompt and returns one of the typed intake
// outcomes so the loop can decide whether to claim or skip the candidate.
//
// The hook preserves operator-supplied passthrough constraints. When the
// resolved route cannot satisfy the strong splitter floor, it returns an
// actionable-but-blocking result with agent_power_unsatisfied in the detail so
// the loop can skip the bead instead of attempting weak decomposition.
func NewPreClaimIntakeHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner) func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
	return func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
		if ctx != nil {
			if err := ctx.Err(); err != nil {
				return PreClaimIntakeResult{}, err
			}
		}
		if strings.TrimSpace(projectRoot) == "" {
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: project root required")
		}
		if !hasBeadLifecycleSkill(projectRoot) {
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: skill missing: bead-lifecycle")
		}
		if store == nil {
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: bead reader required")
		}

		b, err := store.Get(beadID)
		if err != nil {
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: load bead %s: %w", beadID, err)
		}

		prompt, err := buildPreClaimIntakePrompt(projectRoot, store, b)
		if err != nil {
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: build prompt: %w", err)
		}

		strongMinPower := resolveStrongSplitterMinPower(ctx, projectRoot, svc)
		if rcfg.MinPower() > strongMinPower {
			strongMinPower = rcfg.MinPower()
		}

		result, err := dispatchViaResolvedConfig(ctx, projectRoot, svc, runner, rcfg, AgentRunRuntime{
			Prompt:           prompt,
			WorkDir:          projectRoot,
			PromptSource:     PreClaimIntakePromptSource,
			MinPowerOverride: strongMinPower,
		})
		if err != nil {
			if isStrongPowerUnsatisfiedError(err) {
				return PreClaimIntakeResult{
					Outcome: PreClaimIntakeAmbiguousNeedsHuman,
					Detail:  "agent_power_unsatisfied: " + err.Error(),
				}, nil
			}
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: dispatch: %w", err)
		}

		payload, err := intakeResultPayload(result)
		if err != nil {
			return PreClaimIntakeResult{}, err
		}

		var out preClaimIntakePromptResult
		if err := json.Unmarshal([]byte(payload), &out); err != nil {
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
		}

		switch strings.ToLower(strings.TrimSpace(out.Classification)) {
		case "atomic":
			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: strings.TrimSpace(out.Reasoning)}, nil
		case "decomposable":
			return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Detail: strings.TrimSpace(out.Reasoning)}, nil
		case "ambiguous":
			return PreClaimIntakeResult{Outcome: PreClaimIntakeAmbiguousNeedsHuman, Detail: strings.TrimSpace(out.Reasoning)}, nil
		case "":
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification")
		default:
			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: unknown classification %q", out.Classification)
		}
	}
}

func buildPreClaimIntakePrompt(projectRoot string, store BeadReader, b *bead.Bead) (string, error) {
	env := preClaimIntakePromptEnvelope{
		Title:         strings.TrimSpace(b.Title),
		Description:   strings.TrimSpace(b.Description),
		Acceptance:    strings.TrimSpace(b.Acceptance),
		Labels:        append([]string(nil), b.Labels...),
		PriorAttempts: []preClaimIntakeAttempt{},
		Depth:         beadDecompositionDepth(projectRoot, b),
		Parent:        strings.TrimSpace(b.Parent),
		Dependencies:  append([]string(nil), b.DepIDs()...),
	}

	// Prior attempts are optional for the gate. If bead history is available,
	// include the last few attempt/result summaries to help the classifier
	// distinguish a first-pass atomic bead from repeated decomposition.
	if store != nil {
		if eventStore, ok := any(store).(interface {
			Events(id string) ([]bead.BeadEvent, error)
		}); ok {
			if events, err := eventStore.Events(b.ID); err == nil && len(events) > 0 {
				for i := len(events) - 1; i >= 0 && len(env.PriorAttempts) < 5; i-- {
					ev := events[i]
					if ev.Kind != "bead.result" && ev.Kind != "execute-bead" {
						continue
					}
					env.PriorAttempts = append(env.PriorAttempts, preClaimIntakeAttempt{
						Status:    strings.TrimSpace(ev.Summary),
						Rationale: strings.TrimSpace(ev.Body),
					})
				}
			}
		}
	}

	body, err := json.MarshalIndent(env, "", "  ")
	if err != nil {
		return "", err
	}

	var sb strings.Builder
	sb.WriteString("MODE: intake\n")
	sb.WriteString("You are evaluating whether this bead is atomic, decomposable, or ambiguous.\n")
	sb.WriteString("Return exactly one JSON object matching the Complexity Evaluator schema.\n")
	sb.WriteString("Do not include prose or markdown.\n\n")
	sb.WriteString("```json\n")
	sb.Write(body)
	sb.WriteString("\n```\n")
	return sb.String(), nil
}

func intakeResultPayload(result *Result) (string, error) {
	if result == nil {
		return "", fmt.Errorf("pre-claim intake: empty runner result")
	}
	text := strings.TrimSpace(result.CondensedOutput)
	if text == "" {
		text = strings.TrimSpace(result.Output)
	}
	if text == "" {
		return "", fmt.Errorf("pre-claim intake: empty output")
	}
	candidate, ok := extractJSONCandidate(text)
	if !ok {
		return "", fmt.Errorf("pre-claim intake: no JSON object found")
	}
	return candidate, nil
}

const defaultStrongSplitterMinPower = 90

func resolveStrongSplitterMinPower(ctx context.Context, projectRoot string, svc agentlib.FizeauService) int {
	if svc == nil {
		return defaultStrongSplitterMinPower
	}

	models, err := svc.ListModels(ctx, agentlib.ModelFilter{})
	if err != nil {
		return defaultStrongSplitterMinPower
	}
	maxPower := 0
	for _, m := range models {
		if m.Power > maxPower {
			maxPower = m.Power
		}
	}
	if maxPower <= 0 {
		return defaultStrongSplitterMinPower
	}
	return maxPower
}

